
INSERT INTO subjects (school_id, name, code, category, is_islamic, is_vocational)
VALUES ('1db1c085-c9c3-483e-941d-ea3b3f508bc7', 'Chemistry', 'CHM', 'science', false, false);

INSERT INTO exam_questions (school_id, subject_id, question_text, option_a, option_b, option_c, option_d, correct_option, difficulty, explanation)
SELECT 
  '1db1c085-c9c3-483e-941d-ea3b3f508bc7',
  s.id,
  q.question_text, q.option_a, q.option_b, q.option_c, q.option_d, q.correct_option, q.difficulty, q.explanation
FROM subjects s,
(VALUES
  ('Consecutive members of an alkane homologous series differ by', 'CH', 'CH₂', 'CH₃', 'CₙHₙ', 'B', 'easy', 'Each successive member of the alkane series differs by a CH₂ group.'),
  ('If an element has the electronic configuration 1s² 2s² 2p⁶ 3s² 3p², it is', 'a metal', 'an alkaline earth metal', 'an s-block element', 'a p-block element', 'D', 'medium', 'The outermost electrons are in the p orbital, making it a p-block element (Silicon).'),
  ('The three-dimensional shape of methane is', 'hexagonal', 'trigonal', 'linear', 'tetrahedral', 'D', 'easy', 'Methane has a tetrahedral geometry with bond angles of 109.5°.'),
  ('Increasing the pressure of a gas', 'lowers the average kinetic energy', 'decreases the density of the gas', 'decreases the temperature', 'increases the density of the gas', 'D', 'easy', 'Compressing a gas at constant temperature increases its density.'),
  ('The cracking process is very important in the petroleum industry because it', 'gives purer products', 'yields more lubricants', 'yields more engine fuels', 'yields more asphalt', 'C', 'easy', 'Cracking breaks down larger hydrocarbons to produce more petrol and other engine fuels.'),
  ('An element that can exist in two or more structural forms with the same chemical properties exhibits', 'polymerism', 'isotropy', 'isomorphism', 'allotropy', 'D', 'easy', 'Allotropy is the existence of an element in different structural forms (e.g., diamond and graphite).'),
  ('An element is electronegative if', 'it tends to exist in gaseous form', 'its ions dissolve readily in water', 'it has a tendency to lose electrons', 'it has a tendency to gain electrons', 'D', 'easy', 'Electronegative elements have a strong tendency to attract and gain electrons.'),
  ('The colour imparted to a flame by calcium ion is', 'green', 'blue', 'brick-red', 'yellow', 'C', 'medium', 'Calcium ions produce a brick-red colour in flame tests.'),
  ('The mass of an atom is determined by', 'its ionization potential', 'its electrochemical potential', 'the number of protons', 'the number of neutrons and protons', 'D', 'easy', 'Atomic mass is determined by the total number of protons and neutrons in the nucleus.'),
  ('Iron displaces copper from Cu²⁺ solution because', 'iron is in metallic form while copper is ionic', 'copper has greater atomic weight than iron', 'copper metal has more electrons', 'iron is higher in the electrochemical series', 'D', 'medium', 'Iron is more reactive (higher in the electrochemical series) and can displace less reactive copper.'),
  ('Crude petroleum pollutant on waterways can be dispersed by', 'heating to boil off the petroleum', 'mechanically stirring to dissolve it', 'pouring organic solvents', 'spraying with detergents', 'D', 'easy', 'Detergents emulsify oil, breaking it into small droplets that disperse in water.'),
  ('Sodium chloride may be obtained from brine by', 'titration', 'decantation', 'distillation', 'evaporation', 'D', 'easy', 'Evaporation of brine (saltwater) leaves behind solid sodium chloride.'),
  ('Naphthalene when heated melts at 354K. At this temperature the molecules', 'decompose into smaller molecules', 'change their shape', 'are oxidized by atmospheric oxygen', 'become mobile as intermolecular forces break', 'D', 'medium', 'Melting breaks intermolecular van der Waals forces, allowing molecules to move freely.'),
  ('The ratio of molecules in 2g of hydrogen to 16g of oxygen is', '2:1', '1:1', '1:2', '1:4', 'A', 'medium', '2g H₂ = 1 mole = 6.02×10²³ molecules; 16g O₂ = 0.5 mole = 3.01×10²³ molecules. Ratio is 2:1.'),
  ('Which of the following conducts electricity?', 'Sulphur', 'Graphite', 'Diamond', 'Red phosphorus', 'B', 'easy', 'Graphite has delocalized electrons between its carbon layers, allowing it to conduct electricity.'),
  ('Hydrogen diffuses through a porous plug', 'at the same rate as oxygen', 'at a slower rate than oxygen', 'twice as fast as oxygen', 'four times as fast as oxygen', 'D', 'medium', 'Rate of diffusion is inversely proportional to √M. √(32/2) = 4, so hydrogen diffuses 4x faster.'),
  ('Lime-water used for detecting CO₂ is an aqueous solution of', 'Ca(OH)₂', 'CaCO₃', 'Ca(HCO₃)₂', 'CaSO₄', 'A', 'easy', 'Lime water is a saturated solution of calcium hydroxide Ca(OH)₂.'),
  ('When kerosene is heated at high temperature, a lower boiling liquid is obtained. This process is', 'polymerization', 'refining', 'hydrogenation', 'cracking', 'D', 'easy', 'Thermal cracking breaks down larger hydrocarbon molecules into smaller, more useful ones.'),
  ('Alkaline hydrolysis of naturally occurring fats and oils yields', 'fats and acids', 'soaps and glycerol', 'margarine and butter', 'esters', 'B', 'easy', 'Saponification (alkaline hydrolysis) of fats produces soap (sodium/potassium salts of fatty acids) and glycerol.'),
  ('The alkanol obtained from the production of soap is', 'ethanol', 'glycerol', 'methanol', 'propanol', 'B', 'easy', 'Saponification produces glycerol (propane-1,2,3-triol) as a by-product.'),
  ('The flame used by welders in cutting metals is', 'butane gas flame', 'acetylene flame', 'kerosene flame', 'oxy-acetylene flame', 'D', 'easy', 'Oxy-acetylene flames reach very high temperatures (over 3000°C) needed for welding and cutting metals.'),
  ('The hybridization of the carbon atom in ethyne is', 'sp²', 'sp', 'sp³d', 'sp³', 'B', 'medium', 'In ethyne (C₂H₂), each carbon forms a triple bond, requiring sp hybridization.'),
  ('Complete hydrogenation of ethyne yields', 'benzene', 'methane', 'ethene', 'ethane', 'D', 'easy', 'C₂H₂ + 2H₂ → C₂H₆. Complete hydrogenation of ethyne gives ethane.'),
  ('Which substance is used in manufacturing bleaching powder?', 'sulphur dioxide', 'chlorine', 'hydrogen tetraoxosulphate', 'hydrogen sulphide', 'B', 'easy', 'Bleaching powder (CaOCl₂) is made by passing chlorine gas over slaked lime.'),
  ('Sodium hydroxide pellets are', 'deliquescent', 'hygroscopic', 'efflorescent', 'hydrated', 'A', 'medium', 'NaOH pellets are deliquescent—they absorb moisture from air and dissolve in it.'),
  ('Water is said to be hard if it', 'easily forms ice', 'must be warmed to dissolve NaCl', 'forms insoluble scum with soap', 'contains nitrates', 'C', 'easy', 'Hard water contains Ca²⁺ or Mg²⁺ ions that react with soap to form insoluble scum.'),
  ('A piece of sea shell in dilute HCl produces a colourless odorless gas that turns limewater milky. The shell contains', 'sodium chloride', 'ammonium nitrate', 'calcium carbonate', 'calcium chloride', 'C', 'easy', 'CaCO₃ + 2HCl → CaCl₂ + H₂O + CO₂. The CO₂ turns limewater milky.'),
  ('The most abundant substance in the universe is', 'Carbon', 'Air', 'Water', 'Hydrogen', 'D', 'easy', 'Hydrogen is the most abundant element in the universe, making up about 75% of all normal matter.'),
  ('Nitrogen can best be obtained from a mixture of O₂ and N₂ by passing over', 'potassium hydroxide', 'heated gold', 'heated magnesium', 'heated phosphorus', 'D', 'medium', 'Heated phosphorus reacts with oxygen (4P + 5O₂ → 2P₂O₅), leaving nitrogen behind.'),
  ('An aqueous solution of metal salt M gives a white precipitate with NaOH that dissolves in excess. With ammonia it also gives a white precipitate that dissolves in excess. The cation is', 'Zn²⁺', 'Ca²⁺', 'Al³⁺', 'Pb²⁺', 'A', 'medium', 'Zinc hydroxide is amphoteric and dissolves in both excess NaOH and excess ammonia.'),
  ('The movement of liquid molecules from the surface to the gaseous phase is', 'Brownian movement', 'Condensation', 'Evaporation', 'Liquefaction', 'C', 'easy', 'Evaporation is the escape of molecules from the surface of a liquid into the gas phase.'),
  ('An element with atomic number twelve is likely to be', 'electrovalent with valency 1', 'electrovalent with valency 2', 'covalent with valency 2', 'covalent with valency 4', 'B', 'medium', 'Atomic number 12 is magnesium (1s²2s²2p⁶3s²), which loses 2 electrons to form Mg²⁺ (electrovalent, valency 2).'),
  ('The forces holding naphthalene crystals together are', 'coulombic', 'ionic', 'covalent', 'van der Waals', 'D', 'easy', 'Naphthalene is a non-polar molecular solid held together by weak van der Waals forces.'),
  ('A metallic ion X²⁺ with inert gas structure contains 18 electrons. How many protons?', '20', '18', '16', '2', 'A', 'medium', 'If X²⁺ has 18 electrons, the neutral atom had 20 electrons = 20 protons (Calcium).'),
  ('Which physical property decreases across the periodic table?', 'Ionization potential', 'Electron affinity', 'Electronegativity', 'Atomic radius', 'D', 'medium', 'Atomic radius decreases across a period due to increasing nuclear charge pulling electrons closer.'),
  ('The energy change for adding an electron to a gaseous atom is called', 'first ionization energy', 'second ionization energy', 'electron affinity', 'electronegativity', 'C', 'easy', 'Electron affinity is the energy change when an electron is added to a gaseous atom.'),
  ('Tetraoxosulphate (VI) ions are tested using', 'acidified silver nitrate', 'acidified barium chloride', 'lime water', 'dilute hydrochloric acid', 'B', 'easy', 'BaCl₂ + SO₄²⁻ → BaSO₄↓ (white precipitate insoluble in dilute HCl), confirming sulphate ions.'),
  ('Ammonia gas is normally dried with', 'concentrated sulphuric acid', 'quicklime', 'anhydrous calcium chloride', 'magnesium sulphate', 'B', 'medium', 'Quicklime (CaO) is a basic drying agent suitable for drying ammonia, which is alkaline.'),
  ('The iron (III) oxide impurity in bauxite is removed by', 'fractional crystallization in acid', 'dissolution in NaOH and filtration', 'extraction with concentrated ammonia', 'electrolysis of molten mixture', 'B', 'medium', 'Al₂O₃ dissolves in NaOH (being amphoteric) while Fe₂O₃ does not, allowing separation by filtration.'),
  ('Which compound gives lilac flame and white precipitate with acidified BaCl₂?', 'KCl', 'NaNO₃', 'K₂SO₄', 'CaSO₄', 'C', 'medium', 'K₂SO₄ contains K⁺ (lilac flame) and SO₄²⁻ (white precipitate with BaCl₂).'),
  ('The catalyst used in the contact process is', 'Manganese (IV) oxide', 'Manganese (II) tetraoxosulphate', 'Vanadium (V) oxide', 'Iron metal', 'C', 'easy', 'V₂O₅ (vanadium pentoxide) catalyzes the oxidation of SO₂ to SO₃ in the contact process.'),
  ('Gunpowder contains charcoal, sulphur, and KNO₃. The salt functions as', 'an oxidant', 'a reductant', 'a solvent', 'a catalyst', 'A', 'medium', 'KNO₃ provides oxygen for the combustion of charcoal and sulphur, acting as an oxidizing agent.'),
  ('When ethanol is heated with excess concentrated H₂SO₄, it is', 'oxidized to ethene', 'polymerized to polyethene', 'dehydrated to ethene', 'dehydrated to ethyne', 'C', 'easy', 'Concentrated H₂SO₄ acts as a dehydrating agent, removing water from ethanol to form ethene.'),
  ('Which compound is NOT formed by chlorine acting on methane?', 'CH₃Cl', 'C₂H₅Cl', 'CH₂Cl₂', 'CHCl₃', 'B', 'medium', 'Chlorination of methane produces CH₃Cl, CH₂Cl₂, CHCl₃, and CCl₄. C₂H₅Cl is not a product.'),
  ('The general formula of an alkyl halide is', 'CₙH₂ₙ₋₂X', 'CₙH₂ₙ₊₁X', 'CₙH₂ₙ₊₂X', 'CₙH₂ₙX', 'B', 'easy', 'Alkyl halides are derived from alkanes by replacing one H with a halogen: CₙH₂ₙ₊₁X.'),
  ('Nylon and rubber are made by', 'polymerization and saponification', 'polymerization', 'saponification and cracking', 'distillation and polymerization', 'B', 'easy', 'Both nylon (condensation polymer) and rubber (addition polymer) are made by polymerization.'),
  ('Starch can be converted to ethyl alcohol by', 'distillation', 'fermentation', 'isomerization', 'cracking', 'B', 'easy', 'Fermentation by yeast enzymes converts starch/sugars to ethanol and CO₂.'),
  ('Vulcanization of rubber is a process by which', 'isoprene units are joined', 'rubber latex is coagulated', 'sulphur is chemically combined in rubber', 'water is removed from rubber', 'C', 'easy', 'Vulcanization cross-links rubber chains with sulphur, improving strength and elasticity.'),
  ('The bond joining two ethanoic acid molecules in liquid state is', 'a covalent bond', 'an ionic bond', 'a dative covalent bond', 'a hydrogen bond', 'D', 'easy', 'Ethanoic acid molecules form dimers through hydrogen bonding between their -COOH groups.'),
  ('Complete oxidation of propan-1-ol gives', 'propanal', 'propan-2-ol', 'propan-1-one', 'propanoic acid', 'D', 'medium', 'Primary alcohols when fully oxidized give carboxylic acids: propan-1-ol → propanal → propanoic acid.'),
  ('The gas responsible for fatal explosions in coal mines is', 'butane', 'ethene', 'ethane', 'methane', 'D', 'easy', 'Methane (firedamp) accumulates in coal mines and can cause fatal explosions when ignited.'),
  ('Which is a physical change?', 'Bubbling chlorine into water', 'Bubbling chlorine into hydrogen', 'Dissolving sodium chloride in water', 'Passing steam over heated iron', 'C', 'medium', 'Dissolving NaCl in water is physical—no new substance is formed and it can be recovered by evaporation.'),
  ('An acid and its conjugate base', 'neutralize each other to form a salt', 'differ only by a proton', 'differ only by opposite charges', 'are always neutral substances', 'B', 'easy', 'According to Brønsted-Lowry theory, an acid and its conjugate base differ by one proton (H⁺).'),
  ('Solid NaOH exposed to air absorbs a gas and gives an alkaline substance with formula', 'NaOH·H₂O', 'NaOH·N₂', 'Na₂CO₃', 'NaHCO₃', 'C', 'medium', 'NaOH absorbs CO₂ from air: 2NaOH + CO₂ → Na₂CO₃ + H₂O.'),
  ('Which is used as an anti-knock in automobile engines?', 'Tetramethyl silane', 'Lead tetra-ethyl', 'Glycerol', 'N-heptane', 'B', 'medium', 'Tetraethyl lead (Pb(C₂H₅)₄) was historically used as an anti-knock additive in petrol.'),
  ('The reaction between ethanoic acid and NaOH is an example of', 'esterification', 'neutralization', 'hydroxylation', 'hydrolysis', 'B', 'easy', 'An acid reacting with a base to form salt and water is neutralization.')
) AS q(question_text, option_a, option_b, option_c, option_d, correct_option, difficulty, explanation)
WHERE s.name = 'Chemistry' AND s.school_id = '1db1c085-c9c3-483e-941d-ea3b3f508bc7';
